INSERT INTO entries (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('c++', 36, 'beginner', 1, '函数定义', '["函数","定义","基础"]', '学习如何定义C++函数的基本结构。', '在C++中，函数是执行特定任务的代码块。函数定义包括四个部分：返回类型、函数名、参数列表和函数体。返回类型指定函数返回的值类型，如果函数不返回值，则使用void。函数名是标识符，用于在程序中调用函数。参数列表是可选的，包含函数接收的输入变量。函数体是花括号内的语句序列，执行具体操作。\n例如，定义一个简单的函数来打印消息。', '["#include <iostream>\\nusing namespace std;\\n\\nvoid sayHello() {\\n    cout << \\"Hello, World!\\" << endl;\\n}"]', '["Hello, World!"]'),
('c++', 37, 'beginner', 1, '无参数函数', '["函数","无参数"]', '了解如何定义和调用没有参数的函数。', '无参数函数不接受任何输入，直接执行任务。定义时参数列表为空或使用void。调用时只需使用函数名后跟括号。\n示例：定义一个函数打印当前日期消息。', '["#include <iostream>\\nusing namespace std;\\n\\nvoid printDate() {\\n    cout << \\"Today is a good day.\\" << endl;\\n}\\n\\nint main() {\\n    printDate();\\n    return 0;\\n}"]', '["Today is a good day."]'),
('c++', 38, 'beginner', 1, '带参数函数', '["函数","参数"]', '学习如何定义带有参数的函数。', '带参数函数可以接受输入值，这些值在调用时传递。参数在函数定义中声明，包括类型和名称。调用函数时，提供实际参数值。\n示例：定义一个函数计算两个整数的和。', '["#include <iostream>\\nusing namespace std;\\n\\nint add(int a, int b) {\\n    return a + b;\\n}\\n\\nint main() {\\n    int result = add(5, 3);\\n    cout << \\"Sum: \\" << result << endl;\\n    return 0;\\n}"]', '["Sum: 8"]'),
('c++', 39, 'beginner', 1, '返回值函数', '["函数","返回值"]', '理解函数如何返回值。', '函数可以使用return语句返回值。返回类型必须与函数定义中指定的类型匹配。返回值可以用于表达式或赋值。\n示例：定义一个函数返回两个数的最大值。', '["#include <iostream>\\nusing namespace std;\\n\\nint max(int x, int y) {\\n    if (x > y) {\\n        return x;\\n    } else {\\n        return y;\\n    }\\n}\\n\\nint main() {\\n    int a = 10, b = 20;\\n    int m = max(a, b);\\n    cout << \\"Maximum: \\" << m << endl;\\n    return 0;\\n}"]', '["Maximum: 20"]'),
('c++', 40, 'beginner', 1, '函数声明', '["函数","声明","原型"]', '学习函数声明或原型的使用。', '函数声明（或原型）告诉编译器函数的名称、返回类型和参数，而不提供函数体。这允许在定义之前调用函数。声明以分号结尾。\n示例：声明一个函数并在之后定义它。', '["#include <iostream>\\nusing namespace std;\\n\\n// 函数声明\\nint multiply(int a, int b);\\n\\nint main() {\\n    int product = multiply(4, 5);\\n    cout << \\"Product: \\" << product << endl;\\n    return 0;\\n}\\n\\n// 函数定义\\nint multiply(int a, int b) {\\n    return a * b;\\n}"]', '["Product: 20"]');